<?php
require_once __DIR__ . '/../includes/functions.php';
require_admin();
$period=$_GET['period'] ?? 'monthly'; if(!in_array($period,['daily','weekly','monthly','yearly'],true)) $period='monthly'; $sales=ReportService::salesByPeriod($period); $best=ReportService::bestSelling(10); $low=Product::lowStock((int)setting('low_stock_threshold','5')); $stats=ReportService::dashboardStats();
$pageTitle='Reports'; $activePage='reports'; require __DIR__.'/../includes/header.php';
?>
<main class="container-fluid admin-shell"><div class="row g-4"><aside class="col-lg-2"><?php require __DIR__.'/../includes/sidebar.php'; ?></aside><section class="col-lg-10"><div class="d-flex justify-content-between align-items-center mb-4"><h1 class="section-title mb-0">Reports & Analytics</h1><form method="get" class="no-loader"><select name="period" class="form-select" onchange="this.form.submit()"><?php foreach(['daily'=>'Daily','weekly'=>'Weekly','monthly'=>'Monthly','yearly'=>'Yearly'] as $k=>$v): ?><option value="<?= $k ?>" <?= $period===$k?'selected':'' ?>><?= $v ?> Sales</option><?php endforeach; ?></select></form></div><div class="row g-3 mb-4"><div class="col-md-4"><div class="card dashboard-card p-3"><small class="text-muted">Total Revenue</small><h3><?= money($stats['revenue']) ?></h3></div></div><div class="col-md-4"><div class="card dashboard-card p-3"><small class="text-muted">Total Orders</small><h3><?= (int)$stats['orders'] ?></h3></div></div><div class="col-md-4"><div class="card dashboard-card p-3"><small class="text-muted">Total Customers</small><h3><?= (int)$stats['customers'] ?></h3></div></div></div><div class="card table-card p-3 mb-4"><h5 class="fw-bold">Revenue Chart</h5><canvas id="reportChart" height="100"></canvas></div><div class="row g-4"><div class="col-xl-6"><div class="card table-card"><div class="card-header bg-white fw-bold"><?= ucfirst($period) ?> Sales</div><table class="table mb-0"><thead class="table-light"><tr><th>Period</th><th>Orders</th><th>Revenue</th></tr></thead><tbody><?php foreach($sales as $s): ?><tr><td><?= e($s['label']) ?></td><td><?= (int)$s['orders'] ?></td><td><?= money($s['revenue']) ?></td></tr><?php endforeach; ?></tbody></table></div></div><div class="col-xl-6"><div class="card table-card"><div class="card-header bg-white fw-bold">Best Selling Products</div><table class="table mb-0"><thead class="table-light"><tr><th>Product</th><th>Sold</th><th>Revenue</th></tr></thead><tbody><?php foreach($best as $b): ?><tr><td><?= e($b['product_name']) ?></td><td><?= (int)$b['sold_qty'] ?></td><td><?= money($b['revenue']) ?></td></tr><?php endforeach; if(!$best): ?><tr><td colspan="3" class="text-center text-muted py-4">No sales yet.</td></tr><?php endif; ?></tbody></table></div></div><div class="col-12"><div class="card table-card"><div class="card-header bg-white fw-bold">Low Stock Products</div><table class="table mb-0"><thead class="table-light"><tr><th>Product</th><th>Category</th><th>Stock</th></tr></thead><tbody><?php foreach($low as $p): ?><tr><td><?= e($p['product_name']) ?></td><td><?= e($p['category_name']) ?></td><td><span class="badge bg-danger"><?= (int)$p['stock_quantity'] ?></span></td></tr><?php endforeach; if(!$low): ?><tr><td colspan="3" class="text-center text-muted py-4">No low stock products.</td></tr><?php endif; ?></tbody></table></div></div></div></section></div></main><script>window.addEventListener('DOMContentLoaded',()=>{const el=document.getElementById('reportChart');if(el&&window.Chart){new Chart(el,{type:'bar',data:{labels:<?= json_encode(array_column($sales,'label')) ?>,datasets:[{label:'Revenue',data:<?= json_encode(array_map('floatval',array_column($sales,'revenue'))) ?>}]},options:{scales:{y:{beginAtZero:true}}}});}});</script>
